UPDATE public.questions SET
  stimulus_text = 'The author of this passage uses several techniques to emphasize a key point. The speaker uses several examples of the point they are making, which are common to the reader, and the speaker uses a conversational tone throughout the passage. What is the most likely reason why the writer uses these techniques? Taken together, these details imply a broader principle that extends beyond the immediate example, though the author stops short of claiming universal proof. Readers must weigh both the evidence presented and the limits the author acknowledges.',
  question_text = 'In this passage, the author most likely uses these techniques to',
